import{_ as a,o,c as i,ag as t}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"Docs Site Deployment (docs.rustchat.io)","description":"","frontmatter":{},"headers":[],"relativePath":"operations/docs-site-deployment.md","filePath":"operations/docs-site-deployment.md","lastUpdated":null}'),s={name:"operations/docs-site-deployment.md"};function l(r,e,c,n,d,h){return o(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="docs-site-deployment-docs-rustchat-io" tabindex="-1">Docs Site Deployment (<code>docs.rustchat.io</code>) <a class="header-anchor" href="#docs-site-deployment-docs-rustchat-io" aria-label="Permalink to &quot;Docs Site Deployment (\`docs.rustchat.io\`)&quot;">​</a></h1><p>This guide describes how to deploy the documentation site automatically from GitHub Actions to Cloudflare Pages.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><ul><li>Source of truth: <code>docs/</code> directory in this repository</li><li>Static site generator: VitePress</li><li>CI/CD workflow: <code>.github/workflows/docs-ci-cd.yml</code></li><li>Deployment method: Cloudflare Pages Direct Upload via Wrangler in GitHub Actions</li></ul><h2 id="_1-create-a-cloudflare-pages-project" tabindex="-1">1. Create a Cloudflare Pages Project <a class="header-anchor" href="#_1-create-a-cloudflare-pages-project" aria-label="Permalink to &quot;1. Create a Cloudflare Pages Project&quot;">​</a></h2><p>In Cloudflare Dashboard:</p><ol><li>Go to <code>Workers &amp; Pages</code></li><li>Create a new <code>Pages</code> project</li><li>Use any temporary source (the workflow deploys artifacts directly)</li><li>Note the project name (for example <code>rustchat-docs</code>)</li></ol><h2 id="_2-create-api-token" tabindex="-1">2. Create API Token <a class="header-anchor" href="#_2-create-api-token" aria-label="Permalink to &quot;2. Create API Token&quot;">​</a></h2><p>Create a Cloudflare API token with Pages edit permissions for your account/project.</p><p>You also need your Cloudflare Account ID.</p><h2 id="_3-configure-github-secrets" tabindex="-1">3. Configure GitHub Secrets <a class="header-anchor" href="#_3-configure-github-secrets" aria-label="Permalink to &quot;3. Configure GitHub Secrets&quot;">​</a></h2><p>Set these repository secrets:</p><ul><li><code>CLOUDFLARE_API_TOKEN</code></li><li><code>CLOUDFLARE_ACCOUNT_ID</code></li><li><code>CLOUDFLARE_PAGES_PROJECT_NAME</code> (for example <code>rustchat-docs</code>)</li></ul><h2 id="_4-workflow-behavior" tabindex="-1">4. Workflow Behavior <a class="header-anchor" href="#_4-workflow-behavior" aria-label="Permalink to &quot;4. Workflow Behavior&quot;">​</a></h2><ul><li>On pull requests: runs docs link checks and builds the VitePress site.</li><li>On push to <code>main</code>: runs the same checks, then deploys to the Cloudflare Pages project.</li></ul><h2 id="_5-configure-custom-domain" tabindex="-1">5. Configure Custom Domain <a class="header-anchor" href="#_5-configure-custom-domain" aria-label="Permalink to &quot;5. Configure Custom Domain&quot;">​</a></h2><p>In the Pages project:</p><ol><li>Open <code>Custom domains</code></li><li>Add <code>docs.rustchat.io</code></li><li>Complete DNS validation if required</li></ol><p>Cloudflare manages TLS automatically once the domain is attached.</p><h2 id="_6-manual-validation" tabindex="-1">6. Manual Validation <a class="header-anchor" href="#_6-manual-validation" aria-label="Permalink to &quot;6. Manual Validation&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ci</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs:check-links</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs:build</span></span></code></pre></div><p>If CI succeeds and secrets are configured, <code>docs.rustchat.io</code> updates automatically after merge to <code>main</code>.</p>`,22)])])}const m=a(s,[["render",l]]);export{u as __pageData,m as default};
